type SearchCompareFn = unsafe extern "C" fn(*const c_void, *const c_void) -> c_int;
type TreeInsertFn =
    unsafe extern "C" fn(*const c_void, *mut *mut c_void, SearchCompareFn) -> *mut c_void;
type TreeFindFn =
    unsafe extern "C" fn(*const c_void, *const *mut c_void, SearchCompareFn) -> *mut c_void;
type TreeDeleteFn =
    unsafe extern "C" fn(*const c_void, *mut *mut c_void, SearchCompareFn) -> *mut c_void;
type LinearFindFn = unsafe extern "C" fn(
    *const c_void,
    *const c_void,
    *mut usize,
    usize,
    SearchCompareFn,
) -> *mut c_void;
type LinearSearchFn = unsafe extern "C" fn(
    *const c_void,
    *mut c_void,
    *mut usize,
    usize,
    SearchCompareFn,
) -> *mut c_void;
type QueueInsertFn = unsafe extern "C" fn(*mut c_void, *mut c_void);
type QueueRemoveFn = unsafe extern "C" fn(*mut c_void);
type DlIteratePhdrCallback =
    unsafe extern "C" fn(*mut libc::dl_phdr_info, usize, *mut c_void) -> c_int;

#[repr(C)]
#[derive(Clone, Copy)]
enum HostAction {
    Find = 0,
    Enter = 1,
}

#[repr(C)]
#[derive(Clone, Copy)]
struct HostEntry {
    key: *mut c_char,
    data: *mut c_void,
}

#[repr(C)]
#[derive(Default)]
struct HostHsearchData {
    table: *mut c_void,
    size: u32,
    filled: u32,
}

#[repr(C)]
struct ImplHsearchDataView {
    table: *mut c_void,
    size: c_uint,
    filled: c_uint,
}

#[repr(C)]
#[derive(Clone, Copy)]
#[allow(dead_code)]
enum HostVisit {
    Preorder = 0,
    Postorder = 1,
    Endorder = 2,
    Leaf = 3,
}

#[repr(C)]
struct QueueNode {
    next: *mut QueueNode,
    prev: *mut QueueNode,
    value: c_int,
}

impl QueueNode {
    fn new(value: c_int) -> Self {
        Self {
            next: std::ptr::null_mut(),
            prev: std::ptr::null_mut(),
            value,
        }
    }
}

