fn should_use_string_memory_hotpath_fixture(function: &str, inputs: &serde_json::Value) -> bool {
    inputs.get("symbol").and_then(serde_json::Value::as_str) == Some(function)
        && inputs.get("expected").is_some()
        && matches!(
            function,
            "mempcpy"
                | "psignal"
                | "rawmemchr"
                | "re_compile_fastmap"
                | "re_compile_pattern"
                | "re_match"
                | "re_match_2"
                | "re_search"
                | "re_search_2"
                | "re_set_registers"
                | "re_set_syntax"
                | "regerror"
                | "regfree"
                | "stpcpy"
                | "stpncpy"
                | "strcasecmp"
                | "strcasecmp_l"
                | "strcasestr"
                | "strcoll"
                | "strcspn"
                | "strdup"
                | "strndup"
                | "strncasecmp"
                | "strncasecmp_l"
                | "strnlen"
                | "strnstr"
                | "strncmp"
                | "strpbrk"
                | "strsep"
                | "strsignal"
                | "strspn"
                | "strverscmp"
                | "strxfrm"
        )
}

