fn run_host_hsearch_r_replace(
    capacity: usize,
    key: &str,
    first_data: usize,
    second_data: usize,
) -> Result<String, String> {
    let key_cstr = CString::new(key).map_err(|err| err.to_string())?;
    let key_ptr = key_cstr.as_ptr() as *mut c_char;
    let mut htab = HostHsearchData::default();

    unsafe {
        if host_hcreate_r(capacity, &mut htab) == 0 {
            return Err(String::from("host hcreate_r failed"));
        }

        let mut enter_first: *mut HostEntry = std::ptr::null_mut();
        let mut enter_second: *mut HostEntry = std::ptr::null_mut();
        let mut find_result: *mut HostEntry = std::ptr::null_mut();

        if host_hsearch_r(
            HostEntry {
                key: key_ptr,
                data: first_data as *mut c_void,
            },
            HostAction::Enter,
            &mut enter_first,
            &mut htab,
        ) == 0
        {
            host_hdestroy_r(&mut htab);
            return Err(String::from("host hsearch_r first ENTER failed"));
        }
        let enter_first_step = format_hash_step("ENTER", host_entry_payload(enter_first));

        if host_hsearch_r(
            HostEntry {
                key: key_ptr,
                data: second_data as *mut c_void,
            },
            HostAction::Enter,
            &mut enter_second,
            &mut htab,
        ) == 0
        {
            host_hdestroy_r(&mut htab);
            return Err(String::from("host hsearch_r second ENTER failed"));
        }
        let enter_second_step = format_hash_step("ENTER", host_entry_payload(enter_second));

        if host_hsearch_r(
            HostEntry {
                key: key_ptr,
                data: std::ptr::null_mut(),
            },
            HostAction::Find,
            &mut find_result,
            &mut htab,
        ) == 0
        {
            host_hdestroy_r(&mut htab);
            return Err(String::from("host hsearch_r FIND failed"));
        }
        let find_step = format_hash_step("FIND", host_entry_payload(find_result));

        let output = [
            enter_first_step,
            enter_second_step,
            find_step,
            format!("FILLED:{}", htab.filled),
        ]
        .join("|");
        host_hdestroy_r(&mut htab);
        Ok(output)
    }
}

fn run_impl_hsearch_r_replace(
    capacity: usize,
    key: &str,
    first_data: usize,
    second_data: usize,
) -> Result<String, String> {
    let key_cstr = CString::new(key).map_err(|err| err.to_string())?;
    let key_ptr = key_cstr.as_ptr() as *mut c_char;
    let mut htab: frankenlibc_abi::search_abi::HsearchData = unsafe { std::mem::zeroed() };

    unsafe {
        if frankenlibc_abi::search_abi::hcreate_r(capacity, &mut htab) == 0 {
            return Err(String::from("impl hcreate_r failed"));
        }

        let mut enter_first: *mut frankenlibc_abi::search_abi::Entry = std::ptr::null_mut();
        let mut enter_second: *mut frankenlibc_abi::search_abi::Entry = std::ptr::null_mut();
        let mut find_result: *mut frankenlibc_abi::search_abi::Entry = std::ptr::null_mut();

        if frankenlibc_abi::search_abi::hsearch_r(
            frankenlibc_abi::search_abi::Entry {
                key: key_ptr,
                data: first_data as *mut c_void,
            },
            impl_hash_action(frankenlibc_abi::search_abi::Action::ENTER),
            &mut enter_first,
            &mut htab,
        ) == 0
        {
            frankenlibc_abi::search_abi::hdestroy_r(&mut htab);
            return Err(String::from("impl hsearch_r first ENTER failed"));
        }
        let enter_first_step = format_hash_step("ENTER", impl_entry_payload(enter_first));

        if frankenlibc_abi::search_abi::hsearch_r(
            frankenlibc_abi::search_abi::Entry {
                key: key_ptr,
                data: second_data as *mut c_void,
            },
            impl_hash_action(frankenlibc_abi::search_abi::Action::ENTER),
            &mut enter_second,
            &mut htab,
        ) == 0
        {
            frankenlibc_abi::search_abi::hdestroy_r(&mut htab);
            return Err(String::from("impl hsearch_r second ENTER failed"));
        }
        let enter_second_step = format_hash_step("ENTER", impl_entry_payload(enter_second));

        if frankenlibc_abi::search_abi::hsearch_r(
            frankenlibc_abi::search_abi::Entry {
                key: key_ptr,
                data: std::ptr::null_mut(),
            },
            impl_hash_action(frankenlibc_abi::search_abi::Action::FIND),
            &mut find_result,
            &mut htab,
        ) == 0
        {
            frankenlibc_abi::search_abi::hdestroy_r(&mut htab);
            return Err(String::from("impl hsearch_r FIND failed"));
        }
        let find_step = format_hash_step("FIND", impl_entry_payload(find_result));

        let output = [
            enter_first_step,
            enter_second_step,
            find_step,
            format!("FILLED:{}", impl_hsearch_filled(&htab)),
        ]
        .join("|");
        frankenlibc_abi::search_abi::hdestroy_r(&mut htab);
        Ok(output)
    }
}

fn tree_node_value(node: *mut c_void) -> Option<c_int> {
    if node.is_null() {
        None
    } else {
        Some(unsafe { *(*(node as *const *const c_int)) })
    }
}

fn build_tree(search_fn: TreeInsertFn, keys: &[c_int]) -> (*mut c_void, Vec<c_int>, Option<c_int>) {
    let mut root: *mut c_void = std::ptr::null_mut();
    let stored_keys = keys.to_vec();
    let mut first_inserted_value = None;

    for key in &stored_keys {
        let node =
            unsafe { search_fn((key as *const c_int).cast(), &mut root, search_int_compare) };
        if first_inserted_value.is_none() {
            first_inserted_value = tree_node_value(node);
        }
    }

    (root, stored_keys, first_inserted_value)
}

fn cleanup_tree(delete_fn: TreeDeleteFn, root: &mut *mut c_void, keys: &[c_int]) {
    for key in keys {
        unsafe {
            delete_fn((key as *const c_int).cast(), root, search_int_compare);
        }
    }
}

fn run_tree_insert_find(
    search_fn: TreeInsertFn,
    find_fn: TreeFindFn,
    delete_fn: TreeDeleteFn,
    keys: &[c_int],
    probes: &[c_int],
) -> String {
    let (mut root, stored_keys, first_inserted_value) = build_tree(search_fn, keys);
    let mut parts = vec![match first_inserted_value {
        Some(value) => format!("ROOT:{value}"),
        None => String::from("ROOT:NULL"),
    }];

    for probe in probes {
        let probe_key = *probe;
        let found = unsafe {
            find_fn(
                (&probe_key as *const c_int).cast(),
                &root as *const *mut c_void,
                search_int_compare,
            )
        };
        parts.push(format!(
            "FIND:{probe_key}={}",
            usize::from(!found.is_null())
        ));
    }

    cleanup_tree(delete_fn, &mut root, &stored_keys);
    parts.join("|")
}

fn run_tree_delete(
    search_fn: TreeInsertFn,
    find_fn: TreeFindFn,
    delete_fn: TreeDeleteFn,
    keys: &[c_int],
    delete_key: c_int,
    probes: &[c_int],
) -> String {
    let (mut root, stored_keys, _) = build_tree(search_fn, keys);
    let deleted = unsafe {
        delete_fn(
            (&delete_key as *const c_int).cast(),
            &mut root,
            search_int_compare,
        )
    };
    let mut parts = vec![format!(
        "DELETE:{delete_key}={}",
        usize::from(!deleted.is_null())
    )];

    for probe in probes {
        let probe_key = *probe;
        let found = unsafe {
            find_fn(
                (&probe_key as *const c_int).cast(),
                &root as *const *mut c_void,
                search_int_compare,
            )
        };
        parts.push(format!(
            "FIND:{probe_key}={}",
            usize::from(!found.is_null())
        ));
    }

    cleanup_tree(delete_fn, &mut root, &stored_keys);
    parts.join("|")
}

fn tree_walk_node_value(nodep: *const c_void) -> c_int {
    unsafe { *(*(nodep as *const *const c_int)) }
}

fn host_visit_name(visit: HostVisit) -> &'static str {
    match visit {
        HostVisit::Preorder => "preorder",
        HostVisit::Postorder => "postorder",
        HostVisit::Endorder => "endorder",
        HostVisit::Leaf => "leaf",
    }
}

fn impl_visit_name(visit: frankenlibc_abi::search_abi::Visit) -> &'static str {
    match visit {
        frankenlibc_abi::search_abi::Visit::Preorder => "preorder",
        frankenlibc_abi::search_abi::Visit::Postorder => "postorder",
        frankenlibc_abi::search_abi::Visit::Endorder => "endorder",
        frankenlibc_abi::search_abi::Visit::Leaf => "leaf",
    }
}

unsafe extern "C" fn host_twalk_capture(nodep: *const c_void, visit: HostVisit, level: c_int) {
    let value = tree_walk_node_value(nodep);
    HOST_TWALK_EVENTS.with(|events| {
        events
            .borrow_mut()
            .push(format!("{value}:{}:{level}", host_visit_name(visit)));
    });
}

unsafe extern "C" fn impl_twalk_capture(
    nodep: *const c_void,
    visit: frankenlibc_abi::search_abi::Visit,
    level: c_int,
) {
    let value = tree_walk_node_value(nodep);
    IMPL_TWALK_EVENTS.with(|events| {
        events
            .borrow_mut()
            .push(format!("{value}:{}:{level}", impl_visit_name(visit)));
    });
}

fn run_host_twalk_capture(keys: &[c_int]) -> String {
    let (mut root, stored_keys, _) = build_tree(host_tsearch, keys);
    HOST_TWALK_EVENTS.with(|events| events.borrow_mut().clear());
    unsafe { host_twalk(root, host_twalk_capture) };
    let output = HOST_TWALK_EVENTS.with(|events| events.borrow().join("|"));
    cleanup_tree(host_tdelete, &mut root, &stored_keys);
    output
}

fn run_impl_twalk_capture(keys: &[c_int]) -> String {
    let (mut root, stored_keys, _) = build_tree(frankenlibc_abi::search_abi::tsearch, keys);
    IMPL_TWALK_EVENTS.with(|events| events.borrow_mut().clear());
    unsafe { frankenlibc_abi::search_abi::twalk(root, impl_twalk_capture) };
    let output = IMPL_TWALK_EVENTS.with(|events| events.borrow().join("|"));
    cleanup_tree(
        frankenlibc_abi::search_abi::tdelete,
        &mut root,
        &stored_keys,
    );
    output
}

fn run_linear_find(find_fn: LinearFindFn, base: &[c_int], key: c_int) -> String {
    let data = base.to_vec();
    let mut nel = data.len();
    let result = unsafe {
        find_fn(
            (&key as *const c_int).cast(),
            data.as_ptr().cast(),
            &mut nel,
            std::mem::size_of::<c_int>(),
            search_int_compare,
        )
    };

    if result.is_null() {
        return String::from("NULL");
    }

    let index = unsafe { (result as *const c_int).offset_from(data.as_ptr()) as usize };
    format!("INDEX:{index}")
}

fn run_linear_search(
    search_fn: LinearSearchFn,
    base: &[c_int],
    key: c_int,
    capacity: usize,
) -> String {
    let mut data = base.to_vec();
    data.resize(capacity.max(base.len()), 0);
    let mut nel = base.len();
    let result = unsafe {
        search_fn(
            (&key as *const c_int).cast(),
            data.as_mut_ptr().cast(),
            &mut nel,
            std::mem::size_of::<c_int>(),
            search_int_compare,
        )
    };

    if result.is_null() {
        return String::from("NULL");
    }

    let index = unsafe { (result as *const c_int).offset_from(data.as_ptr()) as usize };
    format!("INDEX:{index}|NEL:{nel}|ARRAY:{:?}", &data[..nel])
}

fn queue_link_value(ptr: *mut QueueNode) -> String {
    if ptr.is_null() {
        String::from("NULL")
    } else {
        unsafe { (*ptr).value.to_string() }
    }
}

fn snapshot_queue(nodes: &[QueueNode]) -> String {
    nodes
        .iter()
        .map(|node| {
            format!(
                "{}(prev={},next={})",
                node.value,
                queue_link_value(node.prev),
                queue_link_value(node.next),
            )
        })
        .collect::<Vec<_>>()
        .join("|")
}

fn run_queue_insert(insert_fn: QueueInsertFn, values: &[c_int]) -> String {
    let mut nodes: Vec<QueueNode> = values.iter().map(|value| QueueNode::new(*value)).collect();
    if nodes.is_empty() {
        return String::from("EMPTY");
    }

    unsafe {
        insert_fn(
            (&mut nodes[0] as *mut QueueNode).cast(),
            std::ptr::null_mut(),
        );
        for idx in 1..nodes.len() {
            let elem = (&mut nodes[idx] as *mut QueueNode).cast();
            let pred = (&mut nodes[idx - 1] as *mut QueueNode).cast();
            insert_fn(elem, pred);
        }
    }

    snapshot_queue(&nodes)
}

fn run_queue_remove(
    insert_fn: QueueInsertFn,
    remove_fn: QueueRemoveFn,
    values: &[c_int],
    remove_value: c_int,
) -> Result<String, String> {
    let mut nodes: Vec<QueueNode> = values.iter().map(|value| QueueNode::new(*value)).collect();
    if nodes.is_empty() {
        return Err(String::from("queue values must not be empty"));
    }

    unsafe {
        insert_fn(
            (&mut nodes[0] as *mut QueueNode).cast(),
            std::ptr::null_mut(),
        );
        for idx in 1..nodes.len() {
            let elem = (&mut nodes[idx] as *mut QueueNode).cast();
            let pred = (&mut nodes[idx - 1] as *mut QueueNode).cast();
            insert_fn(elem, pred);
        }
    }

    let Some(target_index) = nodes.iter().position(|node| node.value == remove_value) else {
        return Err(format!("queue value {remove_value} not present"));
    };
    unsafe { remove_fn((&mut nodes[target_index] as *mut QueueNode).cast()) };

    Ok(snapshot_queue(&nodes))
}

fn ensure_supported_mode(mode: &str) -> Result<(), String> {
    if mode_is_strict(mode) || mode_is_hardened(mode) {
        return Ok(());
    }
    Err(format!("unsupported mode: {mode}"))
}

fn non_host_execution(impl_output: String) -> DifferentialExecution {
    DifferentialExecution {
        host_output: String::from("SKIP"),
        impl_output,
        host_parity: true,
        note: None,
    }
}

fn execute_mntent_getmntent_r_case(
    inputs: &serde_json::Value,
    mode: &str,
) -> Result<DifferentialExecution, String> {
    ensure_supported_mode(mode)?;
    let line = parse_u8_vec_or_string(inputs, "line")?;
    if line.contains(&0) {
        return Err(String::from(
            "getmntent_r fixture line must not contain NUL",
        ));
    }

    let impl_output = impl_mntent_parse_output(&line);
    let host_output = host_mntent_parse_output(&line)?;
    let host_parity = host_output == impl_output;

    Ok(DifferentialExecution {
        host_output,
        impl_output,
        host_parity,
        note: (!host_parity).then(|| String::from("getmntent_r parsed field mismatch")),
    })
}

fn execute_mntent_hasmntopt_case(
    inputs: &serde_json::Value,
    mode: &str,
) -> Result<DifferentialExecution, String> {
    ensure_supported_mode(mode)?;
    let opts = parse_u8_vec_or_string(inputs, "opts")?;
    let needle = parse_u8_vec_or_string_any(inputs, &["opt", "needle"])?;
    if opts.contains(&0) || needle.contains(&0) {
        return Err(String::from(
            "hasmntopt fixture opts/needle must not contain NUL",
        ));
    }

    let impl_output = mntent_offset_output(frankenlibc_core::mntent::has_mnt_opt(&opts, &needle));
    let host_output = host_mntent_hasmntopt_output(&opts, &needle)?;
    let host_parity = host_output == impl_output;

    Ok(DifferentialExecution {
        host_output,
        impl_output,
        host_parity,
        note: (!host_parity).then(|| String::from("hasmntopt token-boundary mismatch")),
    })
}

fn impl_mntent_parse_output(line: &[u8]) -> String {
    match frankenlibc_core::mntent::parse_mntent_line(line) {
        Some(fields) => format_mntent_fields_output(
            fields.fsname,
            fields.dir,
            fields.mtype,
            fields.opts,
            fields.freq,
            fields.passno,
        ),
        None => String::from("NONE"),
    }
}

fn host_mntent_parse_output(line: &[u8]) -> Result<String, String> {
    let mut data = line.to_vec();
    if data.is_empty() {
        data.push(b'\n');
    }
    let mode = CString::new("r").map_err(|err| format!("invalid fmemopen mode: {err}"))?;
    let stream = unsafe {
        // SAFETY: `data` is a live mutable buffer for the lifetime of the FILE and `mode`
        // is a NUL-terminated C string.
        libc::fmemopen(
            data.as_mut_ptr().cast::<c_void>(),
            data.len(),
            mode.as_ptr(),
        )
    };
    if stream.is_null() {
        return Err(String::from("host fmemopen failed"));
    }

    let mut mnt = libc::mntent {
        mnt_fsname: std::ptr::null_mut(),
        mnt_dir: std::ptr::null_mut(),
        mnt_type: std::ptr::null_mut(),
        mnt_opts: std::ptr::null_mut(),
        mnt_freq: 0,
        mnt_passno: 0,
    };
    let mut buffer = vec![0 as c_char; 1024];
    let buflen = c_int::try_from(buffer.len())
        .map_err(|_| String::from("getmntent_r scratch buffer too large for c_int"))?;
    let ptr = unsafe {
        // SAFETY: `stream` is a valid FILE from fmemopen, `mnt` points to writable storage,
        // and `buffer` is a writable scratch buffer of `buflen` bytes.
        libc::getmntent_r(stream, &mut mnt, buffer.as_mut_ptr(), buflen)
    };

    let output = if ptr.is_null() {
        String::from("NONE")
    } else {
        host_mntent_record_output(&mnt)
    };

    let close_rc = unsafe {
        // SAFETY: `stream` was returned by fmemopen and has not been closed yet.
        libc::fclose(stream)
    };
    if close_rc != 0 {
        return Err(format!("host fclose failed with rc={close_rc}"));
    }

    Ok(output)
}

fn host_mntent_hasmntopt_output(opts: &[u8], needle: &[u8]) -> Result<String, String> {
    let opts_c =
        CString::new(opts).map_err(|_| String::from("hasmntopt opts contains interior NUL"))?;
    let needle_c =
        CString::new(needle).map_err(|_| String::from("hasmntopt needle contains interior NUL"))?;
    let ent = libc::mntent {
        mnt_fsname: std::ptr::null_mut(),
        mnt_dir: std::ptr::null_mut(),
        mnt_type: std::ptr::null_mut(),
        mnt_opts: opts_c.as_ptr().cast_mut(),
        mnt_freq: 0,
        mnt_passno: 0,
    };
    let ptr = unsafe {
        // SAFETY: `ent` contains a valid NUL-terminated `mnt_opts` pointer and `needle_c`
        // is a valid NUL-terminated option name for the duration of the call.
        libc::hasmntopt(&ent, needle_c.as_ptr())
    };

    if ptr.is_null() {
        return Ok(String::from("NULL"));
    }

    let offset = unsafe {
        // SAFETY: hasmntopt returns either NULL or a pointer into `mnt_opts`.
        ptr.cast_const().offset_from(opts_c.as_ptr())
    };
    if offset < 0 || usize::try_from(offset).is_err() {
        return Err(String::from("host hasmntopt returned pointer outside opts"));
    }

    Ok(mntent_offset_output(Some(offset as usize)))
}

fn host_mntent_record_output(mnt: &libc::mntent) -> String {
    let fsname = host_cstr_bytes(mnt.mnt_fsname);
    let dir = host_cstr_bytes(mnt.mnt_dir);
    let mtype = host_cstr_bytes(mnt.mnt_type);
    let opts = host_cstr_bytes(mnt.mnt_opts);
    format_mntent_fields_output(&fsname, &dir, &mtype, &opts, mnt.mnt_freq, mnt.mnt_passno)
}

fn host_cstr_bytes(ptr: *const c_char) -> Vec<u8> {
    if ptr.is_null() {
        return b"NULL".to_vec();
    }
    unsafe {
        // SAFETY: libc returned field pointers as NUL-terminated strings in getmntent_r's
        // caller-owned scratch buffer.
        CStr::from_ptr(ptr).to_bytes().to_vec()
    }
}

fn format_mntent_fields_output(
    fsname: &[u8],
    dir: &[u8],
    mtype: &[u8],
    opts: &[u8],
    freq: i32,
    passno: i32,
) -> String {
    format!(
        "fsname={};dir={};type={};opts={};freq={freq};passno={passno}",
        fixture_text_output(fsname),
        fixture_text_output(dir),
        fixture_text_output(mtype),
        fixture_text_output(opts),
    )
}

fn mntent_offset_output(offset: Option<usize>) -> String {
    match offset {
        Some(index) => format!("OFFSET_{index}"),
        None => String::from("NULL"),
    }
}

fn execute_elf64_header_parse_case(
    inputs: &serde_json::Value,
    mode: &str,
) -> Result<DifferentialExecution, String> {
    ensure_supported_mode(mode)?;
    let magic = parse_u8_vec(inputs, "magic")?;
    if magic.len() != 4 {
        return Err(format!("magic must be length 4, got {}", magic.len()));
    }

    let mut header = [0u8; 64];
    header[0..4].copy_from_slice(&magic);
    header[4] = 2; // ELF64
    header[5] = 1; // little-endian

    let impl_output = match frankenlibc_core::elf::Elf64Header::parse(&header) {
        Ok(_) => String::from("Ok"),
        Err(err) => format!("Err({err:?})"),
    };

    Ok(non_host_execution(impl_output))
}

fn execute_compute_relocation_case(
    inputs: &serde_json::Value,
    mode: &str,
) -> Result<DifferentialExecution, String> {
    ensure_supported_mode(mode)?;

    let reloc_type = parse_u64(inputs, "type")? as u32;
    let symbol_value = inputs
        .get("symbol_value")
        .and_then(serde_json::Value::as_u64)
        .unwrap_or(0);
    let base = inputs
        .get("base")
        .and_then(serde_json::Value::as_u64)
        .unwrap_or(0);
    let addend = match inputs.get("addend") {
        Some(value) => value
            .as_i64()
            .or_else(|| value.as_u64().and_then(|v| i64::try_from(v).ok()))
            .ok_or_else(|| String::from("addend must be integer"))?,
        None => 0,
    };

    let reloc = frankenlibc_core::elf::relocation::Elf64Rela {
        r_offset: 0,
        r_info: reloc_type as u64,
        r_addend: addend,
    };
    let ctx = frankenlibc_core::elf::relocation::RelocationContext::new(base);

    let impl_output =
        match frankenlibc_core::elf::relocation::compute_relocation(&reloc, symbol_value, &ctx) {
            Ok((value, size)) => serde_json::json!({
                "value": value,
                "size": size
            })
            .to_string(),
            Err(frankenlibc_core::elf::RelocationResult::Skipped) => String::from("Skipped"),
            Err(frankenlibc_core::elf::RelocationResult::Deferred) => String::from("Deferred"),
            Err(frankenlibc_core::elf::RelocationResult::Overflow) => String::from("Overflow"),
            Err(frankenlibc_core::elf::RelocationResult::Unsupported(code)) => {
                format!("Unsupported({code})")
            }
            Err(other) => format!("{other:?}"),
        };

    Ok(non_host_execution(impl_output))
}

