fn resolver_h_errno_class(value: c_int) -> &'static str {
    match value {
        0 => "OK",
        1 => "HOST_NOT_FOUND",
        2 => "TRY_AGAIN",
        3 => "NO_RECOVERY",
        4 => "NO_DATA",
        _ => "OTHER",
    }
}

