fn run_host_malloc(size: usize) -> bool {
    unsafe {
        let ptr = libc::malloc(size);
        let valid = size == 0 || !ptr.is_null();
        if !ptr.is_null() {
            libc::free(ptr);
        }
        valid
    }
}

fn execute_malloc_case(
    inputs: &serde_json::Value,
    mode: &str,
) -> Result<DifferentialExecution, String> {
    let strict = mode_is_strict(mode);
    let hardened = mode_is_hardened(mode);
    if !strict && !hardened {
        return Err(format!("unsupported mode: {mode}"));
    }

    let size = parse_usize(inputs, "size")?;
    let impl_ptr = unsafe { frankenlibc::frankenlibc_malloc_preview(size) };
    let impl_valid = size == 0 || !impl_ptr.is_null();
    if !impl_ptr.is_null() {
        unsafe { frankenlibc::frankenlibc_free_preview(impl_ptr, size.max(1)) };
    }

    let host_valid = run_host_malloc(size);
    let output_str = |valid: bool| if valid { "ALLOCATED" } else { "NULL" };

    Ok(DifferentialExecution {
        host_output: output_str(host_valid).to_string(),
        impl_output: output_str(impl_valid).to_string(),
        host_parity: host_valid == impl_valid,
        note: if size == 0 {
            Some(String::from(
                "malloc(0) normalized to ALLOCATED because POSIX permits NULL or unique pointer",
            ))
        } else {
            None
        },
    })
}

fn execute_free_case(
    inputs: &serde_json::Value,
    mode: &str,
) -> Result<DifferentialExecution, String> {
    let strict = mode_is_strict(mode);
    let hardened = mode_is_hardened(mode);
    if !strict && !hardened {
        return Err(format!("unsupported mode: {mode}"));
    }

    let ptr_val = parse_usize_any(inputs, &["ptr_val", "size_hint"]).unwrap_or(0);
    if ptr_val == 0 {
        unsafe {
            libc::free(std::ptr::null_mut());
            frankenlibc::frankenlibc_free_preview(std::ptr::null_mut(), 0);
        }
    } else {
        let host_ptr = unsafe { libc::malloc(ptr_val.max(1)) };
        if !host_ptr.is_null() {
            unsafe { libc::free(host_ptr) };
        }
        let impl_ptr = unsafe { frankenlibc::frankenlibc_malloc_preview(ptr_val.max(1)) };
        if !impl_ptr.is_null() {
            unsafe { frankenlibc::frankenlibc_free_preview(impl_ptr, ptr_val.max(1)) };
        }
    }
    Ok(DifferentialExecution {
        host_output: "OK".to_string(),
        impl_output: "OK".to_string(),
        host_parity: true,
        note: None,
    })
}

fn run_host_calloc(nmemb: usize, size: usize) -> (bool, bool) {
    let Some(total) = nmemb.checked_mul(size) else {
        return (false, true);
    };
    unsafe {
        let ptr = libc::calloc(nmemb, size);
        if ptr.is_null() {
            return (total == 0, true);
        }
        let probe_len = total.min(64);
        let zeroed = if total == 0 {
            true
        } else {
            let probe = std::slice::from_raw_parts(ptr.cast::<u8>(), probe_len);
            probe.iter().all(|&b| b == 0)
        };
        libc::free(ptr);
        (true, zeroed)
    }
}

fn execute_calloc_case(
    inputs: &serde_json::Value,
    mode: &str,
) -> Result<DifferentialExecution, String> {
    let strict = mode_is_strict(mode);
    let hardened = mode_is_hardened(mode);
    if !strict && !hardened {
        return Err(format!("unsupported mode: {mode}"));
    }

    let nmemb = parse_usize(inputs, "nmemb")?;
    let size = parse_usize(inputs, "size")?;
    let total = nmemb.checked_mul(size).unwrap_or(0);

    let impl_ptr = unsafe { frankenlibc::frankenlibc_calloc_preview(nmemb, size) };
    let impl_valid = total == 0 || !impl_ptr.is_null();
    let impl_zeroed = if impl_ptr.is_null() || total == 0 {
        true
    } else {
        let probe_len = total.min(64);
        let probe = unsafe { std::slice::from_raw_parts(impl_ptr.cast::<u8>(), probe_len) };
        probe.iter().all(|&b| b == 0)
    };
    if !impl_ptr.is_null() {
        unsafe { frankenlibc::frankenlibc_free_preview(impl_ptr, total.max(1)) };
    }

    let (host_valid, host_zeroed) = run_host_calloc(nmemb, size);
    let output_str = |valid: bool, zeroed: bool| {
        if valid && zeroed {
            "ALLOCATED"
        } else if valid {
            "NONZERO"
        } else {
            "NULL"
        }
    };

    Ok(DifferentialExecution {
        host_output: output_str(host_valid, host_zeroed).to_string(),
        impl_output: output_str(impl_valid, impl_zeroed).to_string(),
        host_parity: host_valid == impl_valid && host_zeroed == impl_zeroed,
        note: None,
    })
}

fn run_host_realloc(ptr_val: usize, old_size: usize, size: usize) -> bool {
    unsafe {
        if ptr_val == 0 {
            let new_ptr = libc::realloc(std::ptr::null_mut(), size);
            let valid = size == 0 || !new_ptr.is_null();
            if !new_ptr.is_null() {
                libc::free(new_ptr);
            }
            valid
        } else {
            let old_ptr = libc::malloc(old_size.max(1));
            if old_ptr.is_null() {
                false
            } else {
                let new_ptr = libc::realloc(old_ptr, size);
                let valid = size == 0 || !new_ptr.is_null();
                if !new_ptr.is_null() {
                    libc::free(new_ptr);
                }
                valid
            }
        }
    }
}

fn execute_realloc_case(
    inputs: &serde_json::Value,
    mode: &str,
) -> Result<DifferentialExecution, String> {
    let strict = mode_is_strict(mode);
    let hardened = mode_is_hardened(mode);
    if !strict && !hardened {
        return Err(format!("unsupported mode: {mode}"));
    }

    let ptr_val = parse_usize_any(inputs, &["ptr_val", "old_size_hint"]).unwrap_or(0);
    let size = parse_usize_any(inputs, &["size", "new_size"])?;
    let old_size = parse_usize_any(inputs, &["old_size", "old_size_hint"]).unwrap_or(ptr_val);

    let impl_valid = if ptr_val == 0 {
        let ptr =
            unsafe { frankenlibc::frankenlibc_realloc_preview(std::ptr::null_mut(), size, 0) };
        let valid = size == 0 || !ptr.is_null();
        if !ptr.is_null() {
            unsafe { frankenlibc::frankenlibc_free_preview(ptr, size.max(1)) };
        }
        valid
    } else {
        let src = unsafe { frankenlibc::frankenlibc_malloc_preview(old_size.max(1)) };
        if src.is_null() {
            false
        } else {
            let ptr =
                unsafe { frankenlibc::frankenlibc_realloc_preview(src, size, old_size.max(1)) };
            let valid = size == 0 || !ptr.is_null();
            if !ptr.is_null() {
                unsafe { frankenlibc::frankenlibc_free_preview(ptr, size.max(1)) };
            }
            valid
        }
    };

    let host_valid = run_host_realloc(ptr_val, old_size, size);
    let output_str = |valid: bool| if valid { "ALLOCATED" } else { "NULL" };

    Ok(DifferentialExecution {
        host_output: output_str(host_valid).to_string(),
        impl_output: output_str(impl_valid).to_string(),
        host_parity: host_valid == impl_valid,
        note: None,
    })
}

fn execute_malloc_membrane_wave01_case(
    function: &str,
    inputs: &serde_json::Value,
    mode: &str,
) -> Result<DifferentialExecution, String> {
    ensure_supported_mode(mode)?;
    let symbol = parse_string(inputs, "symbol")?;
    if symbol != function {
        return Err(format!(
            "malloc/membrane fixture symbol mismatch: function={function}, inputs.symbol={symbol}"
        ));
    }
    let expected = parse_string(inputs, "expected")?;
    let actual = malloc_membrane_symbol_actual(function, inputs)?;

    Ok(non_host_execution(malloc_membrane_fixture_log(
        function, mode, &expected, &actual,
    )))
}

fn malloc_membrane_fixture_log(symbol: &str, mode: &str, expected: &str, actual: &str) -> String {
    let failure_signature = if expected == actual {
        "none"
    } else {
        "mismatch"
    };
    format!(
        "symbol={symbol};mode={mode};expected={expected};actual={actual};failure_signature={failure_signature}"
    )
}

fn malloc_membrane_symbol_actual(
    function: &str,
    inputs: &serde_json::Value,
) -> Result<String, String> {
    match function {
        "__libc_allocate_rtsig" => {
            let high = parse_i32(inputs, "high").unwrap_or(0);
            let rc = unsafe { frankenlibc_abi::glibc_internal_abi::__libc_allocate_rtsig(high) };
            if (34..=64).contains(&rc) {
                if high == 0 {
                    Ok(String::from("RTSIG_LOW_VALID"))
                } else {
                    Ok(String::from("RTSIG_HIGH_VALID"))
                }
            } else {
                Ok(format!("RTSIG_RC_{rc}"))
            }
        }
        "__libc_freeres" => {
            unsafe { frankenlibc_abi::malloc_abi::__libc_freeres() };
            Ok(String::from("FREERES_NOOP_OK"))
        }
        "__libc_init_first" => {
            unsafe {
                frankenlibc_abi::glibc_internal_abi::__libc_init_first(
                    0,
                    std::ptr::null_mut(),
                    std::ptr::null_mut(),
                )
            };
            Ok(String::from("INIT_FIRST_NOOP_OK"))
        }
        "__libc_sa_len" => {
            let af = parse_i32(inputs, "af").unwrap_or(libc::AF_INET);
            let rc = unsafe { frankenlibc_abi::glibc_internal_abi::__libc_sa_len(af as u16) };
            let family = match af {
                x if x == libc::AF_INET => "INET",
                x if x == libc::AF_INET6 => "INET6",
                x if x == libc::AF_UNIX => "UNIX",
                _ => "UNKNOWN",
            };
            Ok(format!("SA_LEN_{family}_{rc}"))
        }
        "aligned_alloc" => {
            let alignment = parse_usize(inputs, "alignment").unwrap_or(64);
            let size = parse_usize(inputs, "size").unwrap_or(128);
            let ptr = unsafe { frankenlibc_abi::malloc_abi::aligned_alloc(alignment, size) };
            if ptr.is_null() {
                return Ok(String::from("ALIGNED_ALLOC_NULL"));
            }
            let aligned = (ptr as usize).is_multiple_of(alignment);
            unsafe { frankenlibc_abi::malloc_abi::free(ptr) };
            if aligned {
                Ok(format!("ALIGNED_ALLOC_{alignment}_{size}_ALIGNED"))
            } else {
                Ok(format!("ALIGNED_ALLOC_{alignment}_{size}_MISALIGNED"))
            }
        }
        "cfree" => {
            let size = parse_usize(inputs, "size").unwrap_or(64);
            let ptr = unsafe { frankenlibc_abi::malloc_abi::malloc(size) };
            if ptr.is_null() {
                return Ok(String::from("CFREE_ALLOC_NULL"));
            }
            unsafe { frankenlibc_abi::malloc_abi::cfree(ptr) };
            Ok(String::from("CFREE_FREED_ALLOCATED"))
        }
        "mallinfo" => {
            seed_malloc_stats_for_fixture();
            let info = unsafe { frankenlibc_abi::malloc_abi::mallinfo() };
            Ok(format!(
                "MALLINFO_UORD_{}_FREE_{}",
                info.uordblks, info.fordblks
            ))
        }
        "mallinfo2" => {
            seed_malloc_stats_for_fixture();
            let info = unsafe { frankenlibc_abi::malloc_abi::mallinfo2() };
            Ok(format!(
                "MALLINFO2_UORD_{}_FREE_{}",
                info.uordblks, info.fordblks
            ))
        }
        "malloc_info" => {
            let rc = unsafe { frankenlibc_abi::malloc_abi::malloc_info(0, std::ptr::null_mut()) };
            Ok(format!("MALLOC_INFO_NULL_RC_{rc}"))
        }
        "malloc_stats" => {
            seed_malloc_stats_for_fixture();
            unsafe { frankenlibc_abi::malloc_abi::malloc_stats() };
            Ok(String::from("MALLOC_STATS_EMITTED"))
        }
        "malloc_trim" => {
            let rc = unsafe { frankenlibc_abi::malloc_abi::malloc_trim(0) };
            Ok(format!("MALLOC_TRIM_RC_{rc}"))
        }
        "malloc_usable_size" => {
            let usable =
                unsafe { frankenlibc_abi::malloc_abi::malloc_usable_size(std::ptr::null_mut()) };
            Ok(format!("MALLOC_USABLE_SIZE_NULL_{usable}"))
        }
        "mallopt" => {
            let param = parse_i32(inputs, "param").unwrap_or(1);
            let value = parse_i32(inputs, "value").unwrap_or(0);
            let rc = unsafe { frankenlibc_abi::malloc_abi::mallopt(param, value) };
            Ok(format!("MALLOPT_RC_{rc}"))
        }
        "memalign" => {
            let alignment = parse_usize(inputs, "alignment").unwrap_or(64);
            let size = parse_usize(inputs, "size").unwrap_or(128);
            let ptr = unsafe { frankenlibc_abi::malloc_abi::memalign(alignment, size) };
            classify_aligned_alloc_pointer("MEMALIGN", ptr, alignment, size)
        }
        "posix_memalign" => {
            let alignment = parse_usize(inputs, "alignment").unwrap_or(64);
            let size = parse_usize(inputs, "size").unwrap_or(128);
            let mut out: *mut c_void = std::ptr::null_mut();
            let rc =
                unsafe { frankenlibc_abi::malloc_abi::posix_memalign(&mut out, alignment, size) };
            if rc != 0 {
                return Ok(format!("POSIX_MEMALIGN_{alignment}_{size}_RC_{rc}"));
            }
            classify_aligned_alloc_pointer("POSIX_MEMALIGN", out, alignment, size)
                .map(|class| format!("{class}_RC_0"))
        }
        "pvalloc" => {
            let size = parse_usize(inputs, "size").unwrap_or(123);
            let page_size = fixture_page_size();
            let ptr = unsafe { frankenlibc_abi::malloc_abi::pvalloc(size) };
            classify_page_aligned_alloc_pointer("PVALLOC", ptr, page_size, size)
        }
        "valloc" => {
            let size = parse_usize(inputs, "size").unwrap_or(256);
            let page_size = fixture_page_size();
            let ptr = unsafe { frankenlibc_abi::malloc_abi::valloc(size) };
            classify_page_aligned_alloc_pointer("VALLOC", ptr, page_size, size)
        }
        other => Err(format!("unsupported malloc/membrane fixture: {other}")),
    }
}

fn classify_aligned_alloc_pointer(
    label: &str,
    ptr: *mut c_void,
    alignment: usize,
    size: usize,
) -> Result<String, String> {
    if ptr.is_null() {
        return Ok(format!("{label}_{alignment}_{size}_NULL"));
    }
    let aligned = (ptr as usize).is_multiple_of(alignment);
    unsafe { frankenlibc_abi::malloc_abi::free(ptr) };
    if aligned {
        Ok(format!("{label}_{alignment}_{size}_ALIGNED"))
    } else {
        Ok(format!("{label}_{alignment}_{size}_MISALIGNED"))
    }
}

fn classify_page_aligned_alloc_pointer(
    label: &str,
    ptr: *mut c_void,
    page_size: usize,
    size: usize,
) -> Result<String, String> {
    if ptr.is_null() {
        return Ok(format!("{label}_{size}_NULL"));
    }
    let aligned = (ptr as usize).is_multiple_of(page_size);
    unsafe { frankenlibc_abi::malloc_abi::free(ptr) };
    if aligned {
        Ok(format!("{label}_{size}_PAGE_ALIGNED"))
    } else {
        Ok(format!("{label}_{size}_PAGE_MISALIGNED"))
    }
}

fn fixture_page_size() -> usize {
    let page_size = unsafe { libc::sysconf(libc::_SC_PAGESIZE) };
    if page_size > 0 {
        page_size as usize
    } else {
        4096
    }
}

fn seed_malloc_stats_for_fixture() {
    frankenlibc_abi::malloc_abi::malloc_stats_init_for_tests();
    frankenlibc_abi::malloc_abi::malloc_stats_reset_for_harness();
    frankenlibc_abi::malloc_abi::malloc_stats_record_alloc_for_harness(256);
    frankenlibc_abi::malloc_abi::malloc_stats_record_free_for_harness(64);
}

fn run_host_atoi(s: &[u8]) -> i32 {
    let mut s_safe = s.to_vec();
    if !s_safe.contains(&0) {
        s_safe.push(0);
    }
    unsafe { libc::atoi(s_safe.as_ptr().cast()) }
}

fn execute_atoi_case(
    inputs: &serde_json::Value,
    mode: &str,
) -> Result<DifferentialExecution, String> {
    let s = parse_c_bytes_any(inputs, &["s", "nptr"])?;
    let strict = mode_is_strict(mode);
    let hardened = mode_is_hardened(mode);
    if !strict && !hardened {
        return Err(format!("unsupported mode: {mode}"));
    }

    let has_nul = s.contains(&0);
    let impl_val = frankenlibc_core::stdlib::atoi(&s[..s.len().saturating_sub(1)]);
    let impl_output = impl_val.to_string();

    if strict && !has_nul {
        return Ok(DifferentialExecution {
            host_output: String::from("UB"),
            impl_output: String::from("UB"),
            host_parity: true,
            note: Some(String::from(
                "strict mode leaves undefined behavior undefined",
            )),
        });
    }

    let host_output = run_host_atoi(&s).to_string();
    let host_parity = host_output == impl_output;

    Ok(DifferentialExecution {
        host_output,
        impl_output,
        host_parity,
        note: None,
    })
}

