fn unistd_process_fixture_log(symbol: &str, mode: &str, expected: &str, actual: &str) -> String {
    let failure_signature = if expected == actual {
        "none"
    } else {
        "mismatch"
    };
    format!(
        "symbol={symbol};mode={mode};expected={expected};actual={actual};failure_signature={failure_signature}"
    )
}

#[repr(C, align(16))]
struct FixtureAiocb {
    bytes: [u8; 256],
}

impl FixtureAiocb {
    const FILDES: usize = 0;
    const BUF: usize = 16;
    const NBYTES: usize = 24;
    const ERROR_CODE: usize = 112;
    const RETURN_VALUE: usize = 120;
    const OFFSET: usize = 128;

    fn new() -> Self {
        Self { bytes: [0; 256] }
    }

    fn as_mut_c_void(&mut self) -> *mut c_void {
        self.bytes.as_mut_ptr().cast::<c_void>()
    }

    fn as_c_void(&self) -> *const c_void {
        self.bytes.as_ptr().cast::<c_void>()
    }

    fn write_i32(&mut self, offset: usize, value: c_int) {
        // SAFETY: FixtureAiocb is 16-byte aligned and all i32 offsets used here
        // match glibc x86_64 aiocb field alignment.
        unsafe {
            self.bytes
                .as_mut_ptr()
                .add(offset)
                .cast::<c_int>()
                .write(value);
        }
    }

    fn write_usize(&mut self, offset: usize, value: usize) {
        // SAFETY: FixtureAiocb is 16-byte aligned and all usize offsets used here
        // match glibc x86_64 aiocb field alignment.
        unsafe {
            self.bytes
                .as_mut_ptr()
                .add(offset)
                .cast::<usize>()
                .write(value);
        }
    }

    fn write_i64(&mut self, offset: usize, value: i64) {
        // SAFETY: FixtureAiocb is 16-byte aligned and all i64 offsets used here
        // match glibc x86_64 aiocb field alignment.
        unsafe {
            self.bytes
                .as_mut_ptr()
                .add(offset)
                .cast::<i64>()
                .write(value);
        }
    }

    fn store_error(&mut self, value: c_int) {
        // SAFETY: ERROR_CODE is 4-byte aligned within the aligned fixture buffer
        // and is accessed as AtomicI32 by the ABI implementation.
        unsafe {
            let ptr = self.bytes.as_mut_ptr().add(Self::ERROR_CODE) as *const AtomicI32;
            (*ptr).store(value, Ordering::Release);
        }
    }

    fn write_return(&mut self, value: isize) {
        // SAFETY: RETURN_VALUE is pointer-width aligned within the aligned fixture
        // buffer and is accessed as isize by the ABI implementation.
        unsafe {
            self.bytes
                .as_mut_ptr()
                .add(Self::RETURN_VALUE)
                .cast::<isize>()
                .write(value);
        }
    }
}

fn completed_aiocb(return_value: isize) -> FixtureAiocb {
    let mut cb = FixtureAiocb::new();
    cb.store_error(0);
    cb.write_return(return_value);
    cb
}

fn capital_exit_fixture_actual(inputs: &serde_json::Value) -> Result<String, String> {
    let status = parse_i32(inputs, "status").unwrap_or(42);
    let child = unsafe { libc::fork() };
    if child == 0 {
        unsafe { frankenlibc_abi::process_abi::_Exit(status) };
    }
    if child < 0 {
        return Ok(String::from("FORK_FAILED"));
    }

    let mut wait_status = 0;
    let waited = unsafe { libc::waitpid(child, &mut wait_status, 0) };
    if waited != child {
        return Ok(format!("WAITPID_RC_{waited}"));
    }
    if libc::WIFEXITED(wait_status) {
        return Ok(format!("EXIT_STATUS_{}", libc::WEXITSTATUS(wait_status)));
    }
    if libc::WIFSIGNALED(wait_status) {
        return Ok(format!("EXIT_SIGNAL_{}", libc::WTERMSIG(wait_status)));
    }
    Ok(String::from("EXIT_UNKNOWN"))
}

fn capital_fork_fixture_actual() -> Result<String, String> {
    let child = unsafe { frankenlibc_abi::unistd_abi::_Fork() };
    if child == 0 {
        unsafe { libc::_exit(0) };
    }
    if child < 0 {
        return Ok(String::from("FORK_FAILED"));
    }

    let mut wait_status = 0;
    let waited = unsafe { libc::waitpid(child, &mut wait_status, 0) };
    if waited != child {
        return Ok(format!("WAITPID_RC_{waited}"));
    }
    if libc::WIFEXITED(wait_status) && libc::WEXITSTATUS(wait_status) == 0 {
        return Ok(String::from("CHILD_EXIT_0"));
    }
    Ok(String::from("CHILD_EXIT_NONZERO"))
}

fn unistd_process_fixture_dso_handle() -> *mut c_void {
    (&UNISTD_PROCESS_FIXTURE_DSO as *const u8 as *mut u8).cast::<c_void>()
}

fn cxa_atexit_fixture_actual() -> Result<String, String> {
    let dso = unistd_process_fixture_dso_handle();
    unsafe { frankenlibc_abi::unistd_abi::__cxa_finalize(dso) };
    UNISTD_PROCESS_FIXTURE_CXA_CALLBACKS.store(0, Ordering::SeqCst);
    let rc = unsafe {
        frankenlibc_abi::unistd_abi::__cxa_atexit(
            unistd_process_fixture_cxa_callback,
            std::ptr::null_mut(),
            dso,
        )
    };
    if rc == 0 {
        unsafe { frankenlibc_abi::unistd_abi::__cxa_finalize(dso) };
    }
    let callbacks = UNISTD_PROCESS_FIXTURE_CXA_CALLBACKS.load(Ordering::SeqCst);
    Ok(format!("CXA_ATEXIT_RC_{rc}_CALLBACKS_{callbacks}"))
}

fn cxa_finalize_fixture_actual() -> Result<String, String> {
    let dso = unistd_process_fixture_dso_handle();
    unsafe { frankenlibc_abi::unistd_abi::__cxa_finalize(dso) };
    UNISTD_PROCESS_FIXTURE_CXA_CALLBACKS.store(0, Ordering::SeqCst);
    let rc1 = unsafe {
        frankenlibc_abi::unistd_abi::__cxa_atexit(
            unistd_process_fixture_cxa_callback,
            std::ptr::null_mut(),
            dso,
        )
    };
    let rc2 = unsafe {
        frankenlibc_abi::unistd_abi::__cxa_atexit(
            unistd_process_fixture_cxa_callback,
            std::ptr::null_mut(),
            dso,
        )
    };
    if rc1 != 0 || rc2 != 0 {
        unsafe { frankenlibc_abi::unistd_abi::__cxa_finalize(dso) };
        return Ok(format!("CXA_FINALIZE_REGISTER_RC_{rc1}_{rc2}"));
    }
    unsafe { frankenlibc_abi::unistd_abi::__cxa_finalize(dso) };
    let callbacks_after_first = UNISTD_PROCESS_FIXTURE_CXA_CALLBACKS.load(Ordering::SeqCst);
    unsafe { frankenlibc_abi::unistd_abi::__cxa_finalize(dso) };
    let callbacks_after_second = UNISTD_PROCESS_FIXTURE_CXA_CALLBACKS.load(Ordering::SeqCst);
    Ok(format!(
        "CXA_FINALIZE_CALLBACKS_{callbacks_after_first}_SECOND_{callbacks_after_second}"
    ))
}

