fn invalid_isize_error_result(prefix: &str, rc: isize) -> String {
    if rc >= 0 {
        format!("{prefix}_RC_{rc}")
    } else {
        format!(
            "{prefix}_ERROR_{}",
            poll_event_loop_errno_class(poll_event_loop_errno())
        )
    }
}

